(window.webpackJsonp=window.webpackJsonp||[]).push([[509],{804:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">sentence</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">searchWord</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> isPrefixOfWord = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">sentence, searchWord</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> s=sentence.split(<span class=\\"hljs-string\\">\' \'</span>)\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;s.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(s[i].startsWith(searchWord)){\\n      <span class=\\"hljs-keyword\\">return</span> i+<span class=\\"hljs-number\\">1</span>\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n};\\n</code></pre>\\n"],"titleSlug":"check-if-a-word-occurs-as-a-prefix-of-any-word-in-a-sentence","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u5b57\u7b26\u4e32 <code>sentence</code> \u4f5c\u4e3a\u53e5\u5b50\u5e76\u6307\u5b9a\u68c0\u7d22\u8bcd\u4e3a <code>searchWord</code> \uff0c\u5176\u4e2d\u53e5\u5b50\u7531\u82e5\u5e72\u7528 <strong>\u5355\u4e2a\u7a7a\u683c</strong> \u5206\u9694\u7684\u5355\u8bcd\u7ec4\u6210\u3002</p>\\n\\n<p>\u8bf7\u4f60\u68c0\u67e5\u68c0\u7d22\u8bcd <code>searchWord</code> \u662f\u5426\u4e3a\u53e5\u5b50 <code>sentence</code> \u4e2d\u4efb\u610f\u5355\u8bcd\u7684\u524d\u7f00\u3002</p>\\n\\n<ul>\\n\\t<li>\u5982\u679c\xa0<code>searchWord</code> \u662f\u67d0\u4e00\u4e2a\u5355\u8bcd\u7684\u524d\u7f00\uff0c\u5219\u8fd4\u56de\u53e5\u5b50\xa0<code>sentence</code> \u4e2d\u8be5\u5355\u8bcd\u6240\u5bf9\u5e94\u7684\u4e0b\u6807\uff08<strong>\u4e0b\u6807\u4ece 1 \u5f00\u59cb</strong>\uff09\u3002</li>\\n\\t<li>\u5982\u679c <code>searchWord</code> \u662f\u591a\u4e2a\u5355\u8bcd\u7684\u524d\u7f00\uff0c\u5219\u8fd4\u56de\u5339\u914d\u7684\u7b2c\u4e00\u4e2a\u5355\u8bcd\u7684\u4e0b\u6807\uff08<strong>\u6700\u5c0f\u4e0b\u6807</strong>\uff09\u3002</li>\\n\\t<li>\u5982\u679c <code>searchWord</code> \u4e0d\u662f\u4efb\u4f55\u5355\u8bcd\u7684\u524d\u7f00\uff0c\u5219\u8fd4\u56de <strong>-1 </strong>\u3002</li>\\n</ul>\\n\\n<p>\u5b57\u7b26\u4e32 <code>S</code> \u7684 <strong>\u524d\u7f00</strong> \u662f <code>S</code> \u7684\u4efb\u4f55\u524d\u5bfc\u8fde\u7eed\u5b50\u5b57\u7b26\u4e32\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>sentence = \\"i love eating burger\\", searchWord = \\"burg\\"\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\\"burg\\" \u662f \\"burger\\" \u7684\u524d\u7f00\uff0c\u800c \\"burger\\" \u662f\u53e5\u5b50\u4e2d\u7b2c 4 \u4e2a\u5355\u8bcd\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>sentence = \\"this problem is an easy problem\\", searchWord = \\"pro\\"\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>\\"pro\\" \u662f \\"problem\\" \u7684\u524d\u7f00\uff0c\u800c \\"problem\\" \u662f\u53e5\u5b50\u4e2d\u7b2c 2 \u4e2a\u4e5f\u662f\u7b2c 6 \u4e2a\u5355\u8bcd\uff0c\u4f46\u662f\u5e94\u8be5\u8fd4\u56de\u6700\u5c0f\u4e0b\u6807 2 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>sentence = \\"i am tired\\", searchWord = \\"you\\"\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n<strong>\u89e3\u91ca\uff1a</strong>\\"you\\" \u4e0d\u662f\u53e5\u5b50\u4e2d\u4efb\u4f55\u5355\u8bcd\u7684\u524d\u7f00\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>sentence = \\"i use triple pillow\\", searchWord = \\"pill\\"\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>sentence = \\"hello from the other side\\", searchWord = \\"they\\"\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= sentence.length <= 100</code></li>\\n\\t<li><code>1 <= searchWord.length <= 10</code></li>\\n\\t<li><code>sentence</code> \u7531\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u548c\u7a7a\u683c\u7ec4\u6210\u3002</li>\\n\\t<li><code>searchWord</code> \u7531\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u7ec4\u6210\u3002</li>\\n\\t<li>\u524d\u7f00\u5c31\u662f\u7d27\u5bc6\u9644\u7740\u4e8e\u8bcd\u6839\u7684\u8bed\u7d20\uff0c\u4e2d\u95f4\u4e0d\u80fd\u63d2\u5165\u5176\u5b83\u6210\u5206\uff0c\u5e76\u4e14\u5b83\u7684\u4f4d\u7f6e\u662f\u56fa\u5b9a\u7684\u2014\u2014-\u4f4d\u4e8e\u8bcd\u6839\u4e4b\u524d\u3002\uff08\u5f15\u7528\u81ea <a href=\\"https://baike.baidu.com/item/%E5%89%8D%E7%BC%80\\" target=\\"_blank\\">\u524d\u7f00_\u767e\u5ea6\u767e\u79d1</a> \uff09</li>\\n</ul>\\n","title":"1455. \u68c0\u67e5\u5355\u8bcd\u662f\u5426\u4e3a\u53e5\u4e2d\u5176\u4ed6\u5355\u8bcd\u7684\u524d\u7f00","relatedTags":["\u5b57\u7b26\u4e32"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1455"}')}}]);